INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u10-l1','B2','reading','b2-u10','normal',1,'Double Comparatives','The more..., the more... — so sánh kép',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u10-l1-p1','b2-u10-l1','multiple_choice',1,'practice','easy',false,'{"question":"Chọn câu ĐÚNG:","options":[{"id":"a","text":"More you study, more you learn."},{"id":"b","text":"The more you study, the more you learn."},{"id":"c","text":"The more you study, more you learn."}],"correctOptionId":"b","explanationVi":"Cả hai mệnh đề cần ''the''."}'::jsonb),
 ('b2-u10-l1-p2','b2-u10-l1','grammar_fill_blank',2,'practice','easy',false,'{"question":"Điền đúng: ''___ longer we wait, ___ worse the situation gets.''","acceptedAnswers":["The / the"],"explanationVi":"The...the = double comparative."}'::jsonb),
 ('b2-u10-l1-p3','b2-u10-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"proportional","right":"tỷ lệ thuận"},{"left":"diminish","right":"giảm bớt"},{"left":"accelerate","right":"tăng tốc"},{"left":"compound","right":"cộng dồn"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u10-l1-p4','b2-u10-l1','grammar_fill_blank',4,'practice','medium',false,'{"question":"Hoàn thành: ''The ___ (hard) the challenge, the ___ (great) the achievement.''","acceptedAnswers":["harder / greater"],"explanationVi":"Tính từ ngắn: harder, greater."}'::jsonb),
 ('b2-u10-l1-p5','b2-u10-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Bạn càng thực hành nhiều, bạn càng tự tin hơn.","acceptedAnswers":["The more you practise, the more confident you become.","The more you practice, the more confident you get."],"explanationVi":"The more you practise, the more confident..."}'::jsonb),
 ('b2-u10-l1-p6','b2-u10-l1','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi: ''The more harder you try, the more better the results.''","acceptedAnswers":["The harder you try, the better the results."],"explanationVi":"harder/better (không thêm more với -er form)."}'::jsonb),
 ('b2-u10-l1-p7','b2-u10-l1','multiple_choice',7,'practice','medium',false,'{"question":"Câu nào là rút gọn double comparative hợp lệ?","options":[{"id":"a","text":"More the merrier."},{"id":"b","text":"The more, the merrier."},{"id":"c","text":"More, merrier."}],"correctOptionId":"b","explanationVi":"Rút gọn: The more, the merrier."}'::jsonb),
 ('b2-u10-l1-q1','b2-u10-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG:","options":[{"id":"a","text":"The sooner we act, the better."},{"id":"b","text":"The sooner we act, better."},{"id":"c","text":"Sooner we act, the better."}],"correctOptionId":"a","explanationVi":"Cả hai mệnh đề cần ''the''."}'::jsonb),
 ('b2-u10-l1-q2','b2-u10-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền đúng: ''___ more you invest now, ___ greater the returns later.''","acceptedAnswers":["The / the"],"explanationVi":"The...the."}'::jsonb),
 ('b2-u10-l1-q3','b2-u10-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Dạng so sánh đúng trong ''The ___ we delay, the ___ we''ll suffer'':","options":[{"id":"a","text":"more longer / more worse"},{"id":"b","text":"longer / more"},{"id":"c","text":"longer / worse"}],"correctOptionId":"c","explanationVi":"longer (short adj), worse (irregular comparative)."}'::jsonb),
 ('b2-u10-l1-q4','b2-u10-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''The ___ (many) people attend, the ___ (successful) the event.''","acceptedAnswers":["more / more successful"],"explanationVi":"more people; more successful."}'::jsonb),
 ('b2-u10-l1-q5','b2-u10-l1','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"proportional","right":"tỷ lệ thuận"},{"left":"accelerate","right":"tăng tốc"},{"left":"diminish","right":"giảm bớt"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u10-l1-q6','b2-u10-l1','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["you","The","become","exercise","healthier","more","the"],"correctOrder":[1,5,0,3,2,4,6],"explanationVi":"The more you exercise, the healthier you become."}'::jsonb),
 ('b2-u10-l1-q7','b2-u10-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Dịch dùng double comparative: ''Càng trì hoãn, càng tốn kém.''","acceptedAnswers":["The longer we delay, the more expensive it becomes.","The more we delay, the more expensive it gets."],"explanationVi":"The longer/more...the more expensive."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u10-l2','B2','reading','b2-u10','normal',2,'Complex Comparisons','as...as; not as...as; far/much + comparative; the same as',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u10-l2-p1','b2-u10-l2','multiple_choice',1,'practice','easy',false,'{"question":"Chọn câu ĐÚNG (không bằng): ''This phone isn''t ___ expensive ___ the other.''","options":[{"id":"a","text":"more / than"},{"id":"b","text":"as / as"},{"id":"c","text":"so / than"}],"correctOptionId":"b","explanationVi":"Not as...as = không bằng."}'::jsonb),
 ('b2-u10-l2-p2','b2-u10-l2','grammar_fill_blank',2,'practice','easy',false,'{"question":"Điền đúng: ''The new system is ___ (far / efficient) than the old one.''","acceptedAnswers":["far more efficient"],"explanationVi":"far more + long adjective."}'::jsonb),
 ('b2-u10-l2-p3','b2-u10-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"considerably","right":"đáng kể"},{"left":"marginally","right":"không đáng kể"},{"left":"superior to","right":"tốt hơn (trang trọng)"},{"left":"inferior to","right":"kém hơn"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u10-l2-p4','b2-u10-l2','grammar_fill_blank',4,'practice','medium',false,'{"question":"Điền đúng (trang trọng): ''Option A is ___ Option B in terms of reliability.''","acceptedAnswers":["superior to","preferable to"],"explanationVi":"superior to / preferable to + noun."}'::jsonb),
 ('b2-u10-l2-p5','b2-u10-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Kết quả tốt hơn đáng kể so với dự kiến.","acceptedAnswers":["The results were considerably better than expected.","The results were significantly better than expected."],"explanationVi":"considerably/significantly + comparative + than."}'::jsonb),
 ('b2-u10-l2-p6','b2-u10-l2','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi: ''This design is superior than the previous one.''","acceptedAnswers":["This design is superior to the previous one."],"explanationVi":"superior TO (không dùng than)."}'::jsonb),
 ('b2-u10-l2-p7','b2-u10-l2','multiple_choice',7,'practice','medium',false,'{"question":"Điền từ nhấn mạnh khác biệt NHỎ: ''The new version is ___ faster.''","options":[{"id":"a","text":"far"},{"id":"b","text":"slightly"},{"id":"c","text":"considerably"}],"correctOptionId":"b","explanationVi":"slightly/marginally = khác biệt nhỏ."}'::jsonb),
 ('b2-u10-l2-q1','b2-u10-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Câu nào có nghĩa là ''kém bằng''?","options":[{"id":"a","text":"as good as"},{"id":"b","text":"not as good as"},{"id":"c","text":"better than"}],"correctOptionId":"b","explanationVi":"not as good as = kém hơn/không bằng."}'::jsonb),
 ('b2-u10-l2-q2','b2-u10-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền đúng: ''The new drug is ___ more effective than the old one.''","acceptedAnswers":["far","much","a lot","considerably","significantly"],"explanationVi":"far/much/considerably + more effective."}'::jsonb),
 ('b2-u10-l2-q3','b2-u10-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Câu nào ĐÚNG?","options":[{"id":"a","text":"This is more preferable than that."},{"id":"b","text":"This is preferable to that."},{"id":"c","text":"This is preferable than that."}],"correctOptionId":"b","explanationVi":"preferable TO (không dùng than; không thêm more)."}'::jsonb),
 ('b2-u10-l2-q4','b2-u10-l2','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền đúng: ''The two samples are almost ___ to each other.''","acceptedAnswers":["identical"],"explanationVi":"identical to = giống hệt."}'::jsonb),
 ('b2-u10-l2-q5','b2-u10-l2','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"identical to","right":"giống hệt"},{"left":"considerably","right":"đáng kể"},{"left":"inferior to","right":"kém hơn"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u10-l2-q6','b2-u10-l2','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["the","is","new","far","efficient","system","more"],"correctOrder":[3,0,2,1,6,5,4],"explanationVi":"The new system is far more efficient."}'::jsonb),
 ('b2-u10-l2-q7','b2-u10-l2','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Dịch: ''Cách tiếp cận này không tốt bằng cách trước.'' →","acceptedAnswers":["This approach is not as good as the previous one.","This approach isn''t as effective as the previous one."],"explanationVi":"not as...as = không bằng."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u10-l3','B2','reading','b2-u10','normal',3,'Global Issues Vocabulary','Từ vựng vấn đề toàn cầu B2',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u10-l3-p1','b2-u10-l3','vocabulary_match',1,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"inequality","right":"bất bình đẳng"},{"left":"poverty","right":"nghèo đói"},{"left":"deforestation","right":"nạn phá rừng"},{"left":"biodiversity","right":"đa dạng sinh học"}],"explanationVi":"Từ vựng toàn cầu."}'::jsonb),
 ('b2-u10-l3-p2','b2-u10-l3','vocabulary_match',2,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"humanitarian","right":"nhân đạo"},{"left":"sanitation","right":"vệ sinh môi trường"},{"left":"governance","right":"quản trị"},{"left":"disparity","right":"sự chênh lệch"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u10-l3-p3','b2-u10-l3','multiple_choice',3,'practice','easy',false,'{"question":"Điền từ đúng: ''Millions of people were forced into ___ due to conflict.''","options":[{"id":"a","text":"displacement"},{"id":"b","text":"governance"},{"id":"c","text":"sanitation"}],"correctOptionId":"a","explanationVi":"displacement = di dời cưỡng bức."}'::jsonb),
 ('b2-u10-l3-p4','b2-u10-l3','multiple_choice',4,'practice','medium',false,'{"question":"Điền từ đúng: ''The ___ between urban and rural incomes has widened.''","options":[{"id":"a","text":"biodiversity"},{"id":"b","text":"disparity"},{"id":"c","text":"displacement"}],"correctOptionId":"b","explanationVi":"disparity = sự chênh lệch."}'::jsonb),
 ('b2-u10-l3-p5','b2-u10-l3','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Chúng ta cần đầu tư vào phát triển bền vững để giảm nghèo đói.","acceptedAnswers":["We need to invest in sustainable development to reduce poverty.","We must invest in sustainable development to combat poverty."],"explanationVi":"sustainable development + reduce poverty."}'::jsonb),
 ('b2-u10-l3-p6','b2-u10-l3','multiple_choice',6,'practice','medium',false,'{"question":"''The UN promotes ___ development'' — điền từ đúng:","options":[{"id":"a","text":"humanitarian"},{"id":"b","text":"sustainable"},{"id":"c","text":"deforestation"}],"correctOptionId":"b","explanationVi":"sustainable development = phát triển bền vững."}'::jsonb),
 ('b2-u10-l3-p7','b2-u10-l3','vocabulary_match',7,'practice','easy',false,'{"question":"Nối từ còn lại:","pairs":[{"left":"sustainable development","right":"phát triển bền vững"},{"left":"displacement","right":"di dời cưỡng bức"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u10-l3-q1','b2-u10-l3','vocabulary_match',8,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"deforestation","right":"nạn phá rừng"},{"left":"governance","right":"quản trị"},{"left":"disparity","right":"sự chênh lệch"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u10-l3-q2','b2-u10-l3','multiple_choice',9,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''bất bình đẳng''?","options":[{"id":"a","text":"sanitation"},{"id":"b","text":"inequality"},{"id":"c","text":"displacement"}],"correctOptionId":"b","explanationVi":"inequality = bất bình đẳng."}'::jsonb),
 ('b2-u10-l3-q3','b2-u10-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Điền từ đúng: ''___ aid organisations responded to the crisis.''","options":[{"id":"a","text":"Humanitarian"},{"id":"b","text":"Sustainable"},{"id":"c","text":"Deforestation"}],"correctOptionId":"a","explanationVi":"humanitarian aid = viện trợ nhân đạo."}'::jsonb),
 ('b2-u10-l3-q4','b2-u10-l3','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền từ đúng: ''Access to clean water and ___ is a fundamental human right.''","acceptedAnswers":["sanitation"],"explanationVi":"sanitation = vệ sinh môi trường."}'::jsonb),
 ('b2-u10-l3-q5','b2-u10-l3','multiple_choice',12,'quiz','medium',true,'{"question":"''Biodiversity'' đề cập đến điều gì?","options":[{"id":"a","text":"Năng lượng tái tạo"},{"id":"b","text":"Sự đa dạng của các loài sinh vật"},{"id":"c","text":"Phát triển bền vững"}],"correctOptionId":"b","explanationVi":"biodiversity = đa dạng sinh học."}'::jsonb),
 ('b2-u10-l3-q6','b2-u10-l3','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["growing","Income","is","worldwide","inequality"],"correctOrder":[1,0,2,3,4],"explanationVi":"Income inequality is growing worldwide."}'::jsonb),
 ('b2-u10-l3-q7','b2-u10-l3','vocabulary_match',14,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"poverty","right":"nghèo đói"},{"left":"biodiversity","right":"đa dạng sinh học"},{"left":"sustainable development","right":"phát triển bền vững"}],"explanationVi":"Ghép đúng."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u10-l4','B2','reading','b2-u10','normal',4,'A Changing World','Đọc hiểu B2 tổng hợp: Thế giới đang thay đổi',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u10-l4-p1','b2-u10-l4','multiple_choice',1,'practice','easy',false,'{"question":"Theo bài, điều gì nổi bật nhất về thay đổi hiện nay?","options":[{"id":"a","text":"Chỉ có tốc độ"},{"id":"b","text":"Không chỉ tốc độ mà còn phạm vi"},{"id":"c","text":"Chỉ ảnh hưởng đến công nghệ"}],"correctOptionId":"b","explanationVi":"''not just the speed of change, but its scope.''"}'::jsonb),
 ('b2-u10-l4-p2','b2-u10-l4','multiple_choice',2,'practice','easy',false,'{"question":"Nhóm nào chịu hậu quả nhiều nhất từ bất bình đẳng?","options":[{"id":"a","text":"Các nước giàu"},{"id":"b","text":"Nhóm dân số dễ bị tổn thương nhất"},{"id":"c","text":"Các tập đoàn lớn"}],"correctOptionId":"b","explanationVi":"''it is the most vulnerable populations that suffer the most.''"}'::jsonb),
 ('b2-u10-l4-p3','b2-u10-l4','multiple_choice',3,'practice','medium',false,'{"question":"Cấu trúc ''What is needed is not simply more money'' là?","options":[{"id":"a","text":"It-cleft"},{"id":"b","text":"What-cleft (pseudo-cleft)"},{"id":"c","text":"Double comparative"}],"correctOptionId":"b","explanationVi":"What is needed is... = what-cleft."}'::jsonb),
 ('b2-u10-l4-p4','b2-u10-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ trong bài với nghĩa:","pairs":[{"left":"unprecedented","right":"chưa từng có"},{"left":"interconnected","right":"liên kết"},{"left":"disparity","right":"sự chênh lệch"},{"left":"tackle","right":"giải quyết"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u10-l4-p5','b2-u10-l4','multiple_choice',5,'practice','medium',false,'{"question":"''Having ratified international agreements'' là cấu trúc gì?","options":[{"id":"a","text":"Reduced relative clause"},{"id":"b","text":"Perfect participle clause (hành động trước)"},{"id":"c","text":"Non-defining clause"}],"correctOptionId":"b","explanationVi":"Having + V3 = participle clause, hành động trước."}'::jsonb),
 ('b2-u10-l4-p6','b2-u10-l4','multiple_choice',6,'practice','medium',false,'{"question":"Bài kết thúc bằng câu hỏi về điều gì?","options":[{"id":"a","text":"Liệu công nghệ có giải quyết được vấn đề"},{"id":"b","text":"Liệu các nước quyền lực có hành động đủ khẩn cấp"},{"id":"c","text":"Khi nào sẽ đạt mục tiêu phát triển bền vững"}],"correctOptionId":"b","explanationVi":"''whether the world''s most powerful nations will act with the urgency.''"}'::jsonb),
 ('b2-u10-l4-p7','b2-u10-l4','grammar_fill_blank',7,'practice','medium',false,'{"question":"Double comparative trong bài: ''The more governments invest in education, ___ resilient their societies become.''","acceptedAnswers":["the more"],"explanationVi":"the more...the more."}'::jsonb),
 ('b2-u10-l4-q1','b2-u10-l4','multiple_choice',8,'quiz','easy',true,'{"question":"Theo bài, sự chênh lệch giàu nghèo hiện nay như thế nào so với thế hệ trước?","options":[{"id":"a","text":"Nhỏ hơn"},{"id":"b","text":"Như cũ"},{"id":"c","text":"Lớn hơn đáng kể"}],"correctOptionId":"c","explanationVi":"''considerably greater than it was a generation ago.''"}'::jsonb),
 ('b2-u10-l4-q2','b2-u10-l4','multiple_choice',9,'quiz','easy',true,'{"question":"''It is the most vulnerable populations that suffer the most'' — nhấn mạnh điều gì?","options":[{"id":"a","text":"Mức độ đau khổ"},{"id":"b","text":"Nhóm người chịu nhiều nhất"},{"id":"c","text":"Nguyên nhân đau khổ"}],"correctOptionId":"b","explanationVi":"It-cleft nhấn mạnh: it is + the most vulnerable + that."}'::jsonb),
 ('b2-u10-l4-q3','b2-u10-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Relative pronoun nào trong ''systems whereby resources reach those who need them''?","options":[{"id":"a","text":"who"},{"id":"b","text":"whereby"},{"id":"c","text":"Cả hai"}],"correctOptionId":"c","explanationVi":"whereby (system) và who (those who need)."}'::jsonb),
 ('b2-u10-l4-q4','b2-u10-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành double comparative từ bài: ''___ more governments invest, ___ more resilient societies become.''","acceptedAnswers":["The / the"],"explanationVi":"The more...the more."}'::jsonb),
 ('b2-u10-l4-q5','b2-u10-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Từ ''unprecedented'' trong bài có nghĩa là?","options":[{"id":"a","text":"Chậm, thận trọng"},{"id":"b","text":"Chưa từng có, vô tiền khoáng hậu"},{"id":"c","text":"Có thể dự đoán"}],"correctOptionId":"b","explanationVi":"unprecedented = chưa từng xảy ra trước đây."}'::jsonb),
 ('b2-u10-l4-q6','b2-u10-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"tackle","right":"giải quyết"},{"left":"interconnected","right":"liên kết"},{"left":"unprecedented","right":"chưa từng có"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u10-l4-q7','b2-u10-l4','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Viết what-cleft: ''Thế giới cần sự lãnh đạo thông minh hơn.'' →","acceptedAnswers":["What the world needs is smarter leadership.","What the world needs is better governance."],"explanationVi":"What the world needs is..."}'::jsonb);
