 ('b2-u10-l5','B2','reading','b2-u10','unit_review',5,'Unit 10 Review — B2 Final','Ôn tập Unit 10 & Tổng kết B2',20,50,75,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u10-l5-q1','b2-u10-l5','grammar_fill_blank',1,'quiz','easy',true,'{"question":"Điền đúng: ''___ more you learn, ___ more opportunities you have.''","acceptedAnswers":["The / the"],"explanationVi":"Double comparative: The more...the more."}'::jsonb),
 ('b2-u10-l5-q2','b2-u10-l5','multiple_choice',2,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG (considerably):","options":[{"id":"a","text":"The results were more considerable better."},{"id":"b","text":"The results were considerably better."},{"id":"c","text":"The results were considerable better."}],"correctOptionId":"b","explanationVi":"considerably + comparative."}'::jsonb),
 ('b2-u10-l5-q3','b2-u10-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''bất bình đẳng''?","options":[{"id":"a","text":"disparity"},{"id":"b","text":"inequality"},{"id":"c","text":"displacement"}],"correctOptionId":"b","explanationVi":"inequality = bất bình đẳng."}'::jsonb),
 ('b2-u10-l5-q4','b2-u10-l5','grammar_fill_blank',4,'quiz','medium',true,'{"question":"What-cleft: ''The world needs better governance.'' →","acceptedAnswers":["What the world needs is better governance."],"explanationVi":"What the world needs is..."}'::jsonb),
 ('b2-u10-l5-q5','b2-u10-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Câu nào ĐÚNG (superior):","options":[{"id":"a","text":"Option A is superior than Option B."},{"id":"b","text":"Option A is more superior to Option B."},{"id":"c","text":"Option A is superior to Option B."}],"correctOptionId":"c","explanationVi":"superior TO (không dùng than, không thêm more)."}'::jsonb),
 ('b2-u10-l5-q6','b2-u10-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"deforestation","right":"nạn phá rừng"},{"left":"governance","right":"quản trị"},{"left":"humanitarian","right":"nhân đạo"},{"left":"disparity","right":"sự chênh lệch"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u10-l5-q7','b2-u10-l5','grammar_fill_blank',7,'quiz','medium',true,'{"question":"Điền đúng: ''The gap between rich and poor is ___ greater than before.''","acceptedAnswers":["considerably","far","much","significantly"],"explanationVi":"considerably/far/much + greater."}'::jsonb),
 ('b2-u10-l5-q8','b2-u10-l5','sentence_ordering',8,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng (double comparative):","tokens":["invest","societies","more","governments","resilient","The","become","the","more"],"correctOrder":[5,2,0,3,8,1,4,7,6],"explanationVi":"The more governments invest, the more resilient societies become."}'::jsonb),
 ('b2-u10-l5-q9','b2-u10-l5','multiple_choice',9,'quiz','medium',true,'{"question":"''It is education that makes the greatest difference.'' — Cấu trúc này nhấn mạnh điều gì?","options":[{"id":"a","text":"Kết quả của giáo dục"},{"id":"b","text":"Giáo dục là nhân tố quan trọng nhất"},{"id":"c","text":"Sự khác biệt là lớn"}],"correctOptionId":"b","explanationVi":"It-cleft nhấn mạnh: it is + education + that."}'::jsonb),
 ('b2-u10-l5-q10','b2-u10-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Dịch dùng double comparative: ''Chúng ta hành động càng sớm, hậu quả càng ít nghiêm trọng.''","acceptedAnswers":["The sooner we act, the less severe the consequences will be.","The sooner we act, the less serious the consequences."],"explanationVi":"The sooner...the less severe."}'::jsonb);
